VALUES
  ('dietitian-moex-11354', 'dietitian', 'dietitian-moex-093-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '有關「米糠油中毒」的敘述，何者正確？ 是因為米糠中不飽和脂肪酸變質所導致的中毒事件  台灣是唯一發生過米糠油中毒的國家 米糠油中毒患者只有免疫系統及生殖機能受損  是人為疏失所造成的不幸事件', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "019192853fdc", "answer_pdf_sha1": "3763ec3c90be", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 5, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11355', 'dietitian', 'dietitian-moex-093-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '有關「戴奧辛（dioxin）」的敘述，何者不正確？ 可視為一種「環境荷爾蒙（environmental hormone）」  自然界中多因有機化合物燃燒不當所產生 肉食性魚類的戴奧辛含量較草食性魚類低  為親脂性化合物易累積在脂肪組織中', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "019192853fdc", "answer_pdf_sha1": "3763ec3c90be", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 6, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11356', 'dietitian', 'dietitian-moex-093-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '下列何者不是食物中毒常見的「病症（symptoms）」？ 胸悶、心悸  頭痛、頭暈  腹瀉、脫水  腹痛、嘔吐', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "019192853fdc", "answer_pdf_sha1": "3763ec3c90be", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 7, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11357', 'dietitian', 'dietitian-moex-093-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '下列何者與食品中微生物的生長繁殖最無關？ 食品的儲存溫度  食品的酸鹼度  食品的水分含量  室內照明強度', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "019192853fdc", "answer_pdf_sha1": "3763ec3c90be", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 8, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11358', 'dietitian', 'dietitian-moex-093-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '有關「潛在危害性食品（potentially hazardous foods）」的敘述，何者不正確？ 蛋白質與碳水化合物含量高   pH在4.6以下 水活性（water activity）在0.85以上  水產品、畜產品、乳製品為常見的代表性食品', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "019192853fdc", "answer_pdf_sha1": "3763ec3c90be", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 9, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11359', 'dietitian', 'dietitian-moex-093-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '下列有關預防「交互污染（cross contamination）」的敘述，何者不正確？ 分別使用獨立的砧板與刀具處理生食與熟食  先處理熟食再處理生食 冰箱中儲存之熟食應置於生食之下  最好在廚房不同的區域處理生食及熟食', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "019192853fdc", "answer_pdf_sha1": "3763ec3c90be", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 10, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11360', 'dietitian', 'dietitian-moex-093-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '最適合作為食品加工設備的材質是： 鋁  不鏽鋼  塑膠  木頭', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "019192853fdc", "answer_pdf_sha1": "3763ec3c90be", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 11, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11361', 'dietitian', 'dietitian-moex-093-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '影響食品加工及調理器具「清洗效率（cleaning efficiency）」的因素不包括： 室內大氣壓  清潔劑的種類  水流的強度或流速  污物的種類', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "019192853fdc", "answer_pdf_sha1": "3763ec3c90be", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 12, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11362', 'dietitian', 'dietitian-moex-093-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '在我國需要先取得許可證書後方得製造、輸入、販售的食品不包括： 食品添加物  酸性罐頭食品  特殊營養食品  膠囊、錠狀食品', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "019192853fdc", "answer_pdf_sha1": "3763ec3c90be", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 13, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11363', 'dietitian', 'dietitian-moex-093-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '在我國現行之食品衛生管理法中，違法的罰則對「物」的處理不包括： 罰金    定期封存 限期收回改正    限期消毒、改製或採行安全措施', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "019192853fdc", "answer_pdf_sha1": "3763ec3c90be", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 14, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
